    }

    with link = "line.nl.ZEH" {
        track(ze[:zko + 0.49sw, :zko + 1.71km]);
        line_label(:left:s, ze[:zko + 1.7km] << 0.5mo << 0.5mt,
            (-0.2dt, 0dt), "ZEH"
        );
        track(ze[:zko + 1.69km, :oza - 0.49sw]);
    }

    with link = "point.nl.Oostzaan" {
        track(ze[:oza - 0.5sw, :oza + 0.5sw]);
        marker(:right :de.bf :removed, ze[:oza] >> 0.5mo >> 0.5mt);
        station(:bottom :removed,
            ze[:oza] >> 0.5mo >> 0.5mt >> 1sh + (1dt, 0.8dt),
