        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:oza + 0.49sw, :pwe - 0.49sw]);
    }

    with link = "point.nl.Purmerend-Weidevenne" {
        track(ze[:pwe - 0.5sw, :pwe + 0.5sw]);
        marker(:right :de.hp, ze[:pwe] >> 0.5mo >> 0.5mt);
        station(:right, ze[:pwe] >> 0.5md >> 1sh + (2.3dt, 2.8dt),
            "Purmerend Weidevenne", "ZEH: 11,535"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:pwe + 0.49sw, :nka + 0.1dl]);
    }

    with link = "point.nl.Noordhollands-kanaal-Purmerend" {
        marker(:right :de.dkst, ze[:nka] >> 0.5mo >> 0.5mt);
        station(:top:right_align, ze[:nka] << 0.5mo << 0.5mt + (1.5dt, -0.8dt),
