                "Noordhollands kanaal,", "brug o/h – bij Purmerend"
            ),
            "ZEH: 12,440 "
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:nka - 0.1dl, :pur - 0.49sw]);
    }

    with link = "point.nl.Purmerend" {
        track(ze[:pur - 0.5sw, :pur + 0.5sw]);
        marker(:left :de.hp, ze[:pur] << 0.5mo << 0.5mt);
        marker(:left :de.exbf, ze[:pur] << 0.5mo << 0.5mt);
        station(:right, ze[:pur] >> 0.5mo >> 0.5mt + (1.5dt, 1.3dt),
            "Purmerend", "ZEH: 13,136"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:pur + 0.49sw, :pov - 0.49sw]);
    }

    with link = "point.nl.Purmerend-Overwhere" {
        track(ze[:pov - 0.5sw, :pov + 0.5sw]);
        marker(:left :de.bf, ze[:pov] << 0.5mo << 0.5mt);
        station(:top, ze[:pov] << 0.5mo << 0.5mt << 1sh + (-3.5dt, -1dt),
            "Purmerend Overwhere", "ZEH: 14,624"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:pov + 0.49sw, :kwa - 0.49sw]);
    }

    with link = "point.nl.Kwadijk" {
        track(ze[:kwa - 0.5sw, :kwa + 0.5sw]);
        marker(:left :de.bf :removed, ze[:kwa] << 0.5mo << 0.5mt);
        station(:left :removed,
            ze[:kwa] << 0.5mo << 0.5mt << 1sh + (-2.3dt, 0.8dt),
            "Kwadijk", "ZEH: 16,5"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:kwa + 0.49sw, :kwa + 2.01km]);
        line_label(:right:w, ze[:kwa + 2km] >> 0.5mo >> 0.5mt, "ZEH");
        track(ze[:kwa + 1.99km, :mid - 0.49sw]);
    }

    with link = "point.nl.Middelie" {
        track(ze[:mid - 0.5sw, :mid + 0.5sw]);
        marker(:left :de.hp :removed, ze[:mid] << 0.5mo << 0.5mt);
        station(:left :removed,
            ze[:mid] << 0.5mo << 0.5mt << 1sh + (-1.3dt, 1.2dt),
            "Middelie", "ZEH: 20,1"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:mid + 0.49sw, :ohu - 0.49sw]);
    }

    with link = "point.nl.Oosthuizen" {
        track(ze[:ohu - 0.5sw, :ohu + 0.5sw]);
        marker(:left :de.bf :removed, ze[:ohu] << 0.5mo << 0.5mt);
        station(:left :removed,
            ze[:ohu] << 0.5mo << 0.5mt << 1sh + (-1.4dt, 1.1dt),
            "Oosthuizen", "ZEH: 23,1"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:ohu + 0.49sw, :sar - 0.49sw]);
    }

    with link = "point.nl.Schardam" {
        track(ze[:sar - 0.5sw, :sar + 0.5sw]);
        marker(:right :de.hp :removed, ze[:sar] >> 0.5mo >> 0.5mt);
        station(:right :removed,
            ze[:sar] >> 0.5mo >> 0.5mt >> 1sh + (1.5dt, 1.3dt),
