        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:sar + 0.49sw, :ave - 0.49sw]);
    }

    with link = "point.nl.Avenhorn" {
        track(ze[:ave - 0.5sw, :ave + 0.5sw]);
        marker(:left :de.bf :removed, ze[:ave] << 0.5mo << 0.5mt);
        station(:left :removed,
