            "Avenhorn", "ZEH: 27,7"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:ave + 0.49sw, :ave + 2.01km]);
        line_label(:left:e, ze[:ave + 2km] << 0.5mo << 0.5mt,
            (0dt, -0.3dt), "ZEH"
        );
        track(ze[:ave + 1.99km, :hoa - 0.49seg]);
        track(:lor, ze[:hoa - 0.5seg, :hoa - 129m]);
    }

    with link = "point.nl.Hoorn-aansl", railway = :station :single {
        # Sp. 1 (NL ZEH up)
        track(ze[:hoa - 130m, :hoo - 399m] >> 0.5mo);
            # 3A - 3B
            track(:side :nopax,
                    ze[:hoa - 95m] >> 0.5mo
                --  ze[:hoa - 95m + 1dl] << 0.5mo
            );

        # Sp. 2 (NL ZEH nd)
        track(ze[:hoa - 130m, :hoo - 399m] << 0.5mo);
            # 5A - 5B
            track(:side :nopax,
                    ze[:hoa + 1dl] << 0.5mo
                --  ze[:hoa + 2dl] << 1.5mo
            );

        # Sp. 3 (NL HHH)
        track(ze[:hoa, :hoo - 399m] << 1.5mo);

        marker(:right :de.abzw, ze[:hoa] >> 0.5mo >> 0.5mt);
        station(:top, ze[:hoa] << 1.5mo << 0.5mt + (-3dt, -1.5dt),
            span(:small, "Hoorn aansl."),
            hbox(:center:top,
                vbox(:right:top, "[HHH: ", "ZEH: "),
                vbox(:sep:top,
                    hbox(:sep:base, "22,", anchor(), "800]"),
                    hbox(:sep:base, "32,", anchor(), "483")
                )
            )
        );
    }

    with link = "point.nl.Hoorn", railway = :station :single {
        let hm = path("d3.nl.hmb");

        # Sp. 1 (NL ZEH up)
        track(ze[:hoo - 400m, :hoo + 550m] >> 0.5mo);
            # 47A - 47B
            track(:side :nopax,
                    ze[:hoo + 520m - 2dl] >> 0.5mo
                --  ze[:hoo + 520m] << 0.5mo
            );

        # Sp. 2 (NL ZEH nd)
        track(ze[:hoo - 400m, :hoo + 550m] << 0.5mo);
            # 23A - 23B
            track(:side :nopax,
                    ze[:hoo - 210m] << 0.5mo
                --  ze[:hoo - 210m + 1dl] >> 0.5mo
            );
            # 45A - 45B
            track(:side :nopax,
                    ze[:hoo + 520m - 2dl] << 0.5mo
                --  ze[:hoo + 520m] >> 0.5mo
            );

        # Sp. 3 (NL HHH)
        track(
                ze[:hoo - 400m, :hoo + 290m - 1dl] << 1.5mo
            --  ze[:hoo + 290m, :hoo + 291m] << 0.5mo
        );
            # 13A - 13B
            track(:side :nopax,
                    ze[:hoo - 210m + 1dl] << 1.5mo
                --  ze[:hoo - 210m + 2dl] << 0.5mo
            );

        # Sp. 4
        track(:side :nopax, hm[:hoo - 330m, :hoo + 290m - 2dl] << 2.5mo);

        # Sp. 6
        track(:side :nopax,
                hm[:hoo - 330m, :hoo + 290m - 3dl] << 3.5mo
            --  hm[:hoo + 290m - 1dl, :hoo + 290m - 0.9dl] << 1.5mo
        );

        # Sp. 8
        track(:side :nocat :museum,
                hm[:hoo - 60m, :hoo + 290m - 2.3dl] << 4.5mo
        );

        # Sp. 9
        track(:side :nocat :nopax,
                hm[:hoo - 220m, :hoo - 60m + 1dl] << 5.5mo
            --  hm[:hoo - 60m + 2dl, :hoo - 60m + 2.1dl] << 4.5mo
        );
        track(:second :nocat :museum,
                hm[:hoo - 60m + 1dl, :hoo + 290m - 3.3dl] << 5.5mo
            --  hm[:hoo + 290m + 0.7dl, :hoo + 550m] << 1.5mo
        );

        # Sp. 11
        track(:side :nocat :nopax,
                hm[:hoo - 330m, :hoo + 290m - 4.3dl] << 6.5mo
        );

        # Sp. 12
        track(:side :nocat :nopax,
                hm[:hoo - 200m, :hoo + 290m - 5.3dl] << 7.5mo
            --  hm[:hoo + 290m - 3.3dl, :hoo + 290m - 3.2dl] << 5.5mo
        );

        # 1e Perron
        platform(
                ze[:hoo - 20m, :hoo + 260m] >> 0.5mo >> 0.5mt
            --  ze[:hoo + 260m, :hoo - 20m] << 1.2mo << 0.5mt
        );

        # 2e Perron
        platform(
                ze[:hoo - 65m, :hoo + 240m] << 0.5mo << 0.5mt
            --  ze[:hoo + 240m, :hoo + 160m] >> 1.05mo
            --  ze[:hoo + 160m, :hoo - 120m] >> 1.5mo << 0.5mt
            --  ze[:hoo - 120m, :hoo - 65m] << 0.95mo
        );

        # SHM Perron
        platform(:nocat :museum,
                hm[:hoo - 60m + 3dl, :hoo + 290m - 5dl] << 4.5mo
            --  hm[:hoo + 290m - 5dl, :hoo - 60m + 3dl] >> 5.5mo
        );

        marker(:right :de.bf, ze[:hoo] >> 1.2mo >> 0.5mt);
        station(:bottom, ze[:hoo] >> 1.2mo >> 0.5mt >> 1sh + (-0.8dt, 0.5dt),
            span(:bold, "Hoorn"),
            hbox(:center:top,
                vbox(:right:top, span(:nocat, "[HMB: "), "[HHH: ", "ZEH: "),
                vbox(:sep:top,
                    hbox(:sep:base :nocat, "−0,", anchor(), "007]"),
                    hbox(:sep:base, "23,", anchor(), "428]"),
                    hbox(:sep:base, "32,", anchor(), "483")
                )
            )
        );
    }

    with link = "line.nl.ZEH" {
        track(:lor, ze[:hoo + 549m, :hoo.ym]);
        track(:lor, ze[:hoo.ym, :hoo.ym + 0.5seg]);
        track(ze[:hoo.ym + 0.49seg, :hke - 99m]);
    }

    with link = "point.nl.Hoorn-Kersenboogerd", railway = :station :single {
        # Sp. 101 (NL ZEH dn)
        track(
                ze[:hke - 100m, :hke + 450m - 1dl] << 0.5mo
            --  ze[:hke + 450m, :hke + 451m] >> 0.5mo
        );

        # Sp. 102 (NL ZEH up)
        track(ze[:hke - 100m, :hke + 910m] >> 0.5mo);
            track(:side :nopax,
                    ze[:hke + 450m + 1dl] >> 0.5mo
                --  ze[:hke + 450m + 2dl] << 0.5mo
            );

        # Sp. 103
        track(:side :nopax, ze[:hke + 450m - 1dl, :hke + 910m] << 0.5mo);

        platform(
                ze[:hke - 60m, :hke + 220m] << 0.5mo << 0.5mt
            --  ze[:hke + 220m, :hke - 60m] >> 1.2mo >> 0.5mt
        );
        platform(
                ze[:hke - 60m, :hke + 220m] >> 0.5mo >> 0.5mt
            --  ze[:hke + 220m, :hke - 60m] << 1.2mo << 0.5mt
        );

        marker(:right :de.bf, ze[:hke] >> 1.2mo >> 0.5mt);
        station(:right, ze[:hke] >> 1.2mo >> 0.5mt >> 1sh + (1.8dt, 1.8dt),
            "Hoorn Kersenboogerd", "ZEH: 34,780"
        );
    }
}

with detail = 4,
     railway = :first :cat:dc15 :pax
{
