    with link = "point.nl.Bovenkarspel-Flora", railway = :station {
        track(ze[:bof - 135m, :bof + 200m]);

        platform(
                ze[:bof - 105m, :bof + 170m] << 0.5mt
            --  ze[:bof + 170m, :bof - 105m] >> 0.5mt >> 0.7mo
